// ============================================
// 🌦️ KIỂM TRA NGƯỠNG CẢNH BÁO (Lấy Dữ Liệu)
// ============================================
const data = $input.first().json.body;

const rainRate = parseFloat(data.rainRate) || 0;
const rainHour = parseFloat(data.rainHour) || 0;
const temperature = parseFloat(data.temperature) || 0;
const humidity = parseFloat(data.humidity) || 0;

let severity = 'Bình thường';
let hasAlert = false;

// Ngưỡng mưa
if (rainRate > 50) { severity = 'Rất Nguy Hiểm (Ngập lụt)'; hasAlert = true; }
else if (rainRate > 30) { severity = 'Nguy Hiểm (Khả năng ngập cao)'; hasAlert = true; }
else if (rainRate > 15) { severity = 'Cảnh Báo (Mưa to)'; hasAlert = true; }
else if (rainHour > 30) { severity = 'Cảnh Báo (Mưa kéo dài)'; hasAlert = true; }

// Ngưỡng nhiệt
if (temperature > 42) { severity = 'Rất Nguy Hiểm (Nguy cơ cháy rừng)'; hasAlert = true; }
else if (temperature > 40) { severity = 'Nguy Hiểm (Nắng nóng sốc nhiệt)'; hasAlert = true; }
else if (temperature > 38) { severity = 'Cảnh Báo (Nắng nóng gay gắt)'; hasAlert = true; }

// Ngưỡng ẩm thấp + nóng
if (humidity > 0 && humidity < 20 && temperature > 35) {
  severity = 'Cảnh Báo (Nguy cơ hỏa hoạn do hanh khô)'; hasAlert = true;
}

return [{ json: { hasAlert, severity, rainRate, rainHour, temperature, humidity } }];

